def fizzbuzz(n):
    """Return 'fizz' for multiples of 3, 'buzz' for multiples of 5, 'fizzbuzz' for both, else the number."""
    if n % 15 == 0:
        return 'fizzbuzz'
    elif n % 3 == 0:
        return 'fizz'
    elif n % 5 == 0:
        return 'buzz'
    return n

